class Solution:
    def getHappyString(self, n: int, k: int) -> str:
        results = []
        def bt(cur):
            if len(cur) == n:
                results.append(''.join(cur))
                return
            for c in 'abc':
                if not cur or cur[-1] != c:
                    cur.append(c)
                    bt(cur)
                    cur.pop()
        bt([])
        if k > len(results):
            return ''
        return results[k-1]

