var getHappyString = function(n, k) {
    const total = 3 * Math.pow(2, n - 1);
    if (k > total) return '';
    k -= 1;
    const chars = 'abc';
    let perStart = total / 3;
    const firstIdx = Math.floor(k / perStart);
    k = k % perStart;
    const result = [chars[firstIdx]];
    for (let i = 1; i < n; i++) {
        const perChoice = perStart / 2;
        perStart = perChoice;
        const choices = chars.split('').filter(c => c !== result[result.length - 1]);
        const choiceIdx = Math.floor(k / perChoice);
        k = k % perChoice;
        result.push(choices[choiceIdx]);
    }
    return result.join('');
};
